package com.example.systemoptimization

import android.app.Service
import android.content.Intent
import android.os.IBinder
import android.util.Log
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.cancel
import kotlinx.coroutines.launch

class MaintenanceTaskService : Service() {

    companion object {
        const val TAG = "MaintenanceTaskService"
        const val ACTION_RUN_TASK = "com.example.systemoptimization.action.RUN_TASK"
        const val EXTRA_TASK_TYPE = "extra_task_type"
        const val EXTRA_TASK_PAYLOAD = "extra_task_payload"

        const val TASK_SYNC = "sync"
        const val TASK_CLEANUP = "cleanup"
    }

    private val serviceJob = SupervisorJob()
    private val serviceScope = CoroutineScope(Dispatchers.IO + serviceJob)

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        val action = intent?.action
        val taskType = intent?.getStringExtra(EXTRA_TASK_TYPE)
        val payload = intent?.getStringExtra(EXTRA_TASK_PAYLOAD)

        if (action == ACTION_RUN_TASK && !taskType.isNullOrBlank()) {
            serviceScope.launch {
                try {
                    when (taskType) {
                        TASK_SYNC -> performDataSynchronization(payload)
                        TASK_CLEANUP -> performCleanup(payload)
                        else -> Log.w(TAG, "Unknown task type: $taskType")
                    }
                } catch (t: Throwable) {
                    Log.e(TAG, "Task failed: $taskType", t)
                } finally {
                    stopSelf(startId)
                }
            }
        } else {
            Log.w(TAG, "Invalid intent received")
            stopSelf(startId)
        }

        return START_NOT_STICKY
    }

    private fun performDataSynchronization(payload: String?) {
        Log.i(TAG, "Starting data synchronization. payload=$payload")
        Thread.sleep(1500)
        Log.i(TAG, "Data synchronization completed")
    }

    private fun performCleanup(payload: String?) {
        Log.i(TAG, "Starting cleanup. payload=$payload")
        Thread.sleep(1000)
        Log.i(TAG, "Cleanup completed")
    }

    override fun onDestroy() {
        serviceJob.cancel()
        super.onDestroy()
    }
}

<service
    android:name=".MaintenanceTaskService"
    android:exported="true">
